(function () {
  const mocks = [
    {
      id: 'upsc-cse-short-20',
      name: 'UPSC CSE Prelims — Short Mock (20 Questions)',
      template: 'nta',
      examCatalogueId: 'upsc-cse',
      kind: 'mock', scope: 'short', sectionTag: null,
      durationMin: 15,
      marking: { correct: 2, wrong: -0.66, unattempted: 0 },
      allowSectionSwitch: true, timerMode: 'full', calculator: false,
      questionTypes: ['mcq'], languages: ['en'],
      sections: [
        { id: 'gs1', name: 'General Studies I', questions: [
          { id: 'upsc-cse-s20-1', text: 'Which of the following rivers does NOT originate within Indian territory?', options: ['Godavari', 'Brahmaputra', 'Narmada', 'Kaveri'], correct: 1, topic: 'Geography', difficulty: 'easy', explanation: 'The Brahmaputra rises from the Angsi/Chemayungdung glacier in Tibet (where it is called Tsangpo) and enters India in Arunachal Pradesh. Godavari, Narmada and Kaveri all rise within India.' },
          { id: 'upsc-cse-s20-2', text: 'The Lakhota Bird Sanctuary, the Sarus crane and the Rann of Kutch are all associated with which Indian state?', options: ['Rajasthan', 'Gujarat', 'Madhya Pradesh', 'Maharashtra'], correct: 1, topic: 'Environment', difficulty: 'medium', explanation: 'The Rann of Kutch and Lakhota lie in Gujarat, which is also a stronghold of the Sarus crane. Hence Gujarat is the common link.' },
          { id: 'upsc-cse-s20-3', text: 'Which Article of the Indian Constitution abolishes untouchability and forbids its practice in any form?', options: ['Article 14', 'Article 15', 'Article 17', 'Article 19'], correct: 2, topic: 'Polity', difficulty: 'easy-medium', explanation: 'Article 17 abolishes untouchability and makes its practice in any form an offence punishable by law. Article 14 deals with equality before law, 15 with non-discrimination, 19 with freedoms.' },
          { id: 'upsc-cse-s20-4', text: 'The Tebhaga movement of 1946–47, demanding two-thirds of the harvest for sharecroppers, was centred mainly in which region?', options: ['Bengal', 'Bihar', 'Andhra', 'Malabar'], correct: 0, topic: 'History', difficulty: 'medium-hard', explanation: 'The Tebhaga movement was a peasant agitation of sharecroppers (bargadars) in Bengal led by the Kisan Sabha, demanding a two-thirds (tebhaga) share of the crop. The Telangana movement was in Andhra; Malabar saw the Moplah revolt.' },
          { id: 'upsc-cse-s20-5', text: 'In the human body, the hormone insulin is secreted by which group of cells?', options: ['Alpha cells of the islets of Langerhans', 'Beta cells of the islets of Langerhans', 'Cells of the adrenal cortex', 'Parietal cells of the stomach'], correct: 1, topic: 'General Science', difficulty: 'medium', explanation: 'Insulin is secreted by the beta cells of the islets of Langerhans in the pancreas. Alpha cells secrete glucagon, which has the opposite effect.' },
          { id: 'upsc-cse-s20-6', text: 'Which one of the following is a directly elected body whose members the President nominates none of?', options: ['Rajya Sabha', 'Lok Sabha', 'Legislative Council', 'Both Houses of Parliament'], correct: 1, topic: 'Polity', difficulty: 'medium-hard', explanation: 'The Lok Sabha is wholly directly elected; the President nominates no members to it after the 104th Amendment ended Anglo-Indian nominations. The President nominates 12 members to the Rajya Sabha; Legislative Councils have nominated members.' },
          { id: 'upsc-cse-s20-7', text: 'The "Doctrine of Lapse," used to annex princely states, is most closely associated with which Governor-General?', options: ['Lord Wellesley', 'Lord Dalhousie', 'Lord Cornwallis', 'Lord Curzon'], correct: 1, topic: 'History', difficulty: 'easy-medium', explanation: 'Lord Dalhousie applied the Doctrine of Lapse to annex states such as Satara, Jhansi and Nagpur when a ruler died without a natural heir. Wellesley used the Subsidiary Alliance.' },
          { id: 'upsc-cse-s20-8', text: 'A nationally important index, the Wholesale Price Index (WPI) in India, is released by which body?', options: ['Reserve Bank of India', 'Office of the Economic Adviser, Ministry of Commerce and Industry', 'National Statistical Office', 'NITI Aayog'], correct: 1, topic: 'Economy', difficulty: 'hard', explanation: 'The WPI is compiled and released by the Office of the Economic Adviser in the Ministry of Commerce and Industry. The CPI is released by the NSO; the RBI uses CPI as its inflation anchor.' },
          { id: 'upsc-cse-s20-9', text: 'The classical dance form "Sattriya" is associated with which Indian state?', options: ['Odisha', 'Assam', 'Manipur', 'Kerala'], correct: 1, topic: 'Art and Culture', difficulty: 'easy', explanation: 'Sattriya originated in the Vaishnava monasteries (sattras) of Assam, founded by Srimanta Sankardeva, and was recognised as a classical dance form by the Sangeet Natak Akademi.' },
          { id: 'upsc-cse-s20-10', text: 'Carbon credits and the concept of "Nationally Determined Contributions" (NDCs) are associated with which international agreement?', options: ['Montreal Protocol', 'Paris Agreement', 'Ramsar Convention', 'Basel Convention'], correct: 1, topic: 'Environment', difficulty: 'hard', explanation: 'Nationally Determined Contributions are the climate pledges submitted by countries under the 2015 Paris Agreement. The Montreal Protocol addresses ozone-depleting substances, Ramsar wetlands, and Basel hazardous-waste movement.' },
        ]},
        { id: 'csat', name: 'CSAT', questions: [
          { id: 'upsc-cse-s20-11', text: 'Read the passage and answer: "Progress in science depends on doubt, not certainty. A scientist who is sure of an answer stops looking; one who questions keeps searching." Which statement best reflects the author\'s view?', options: ['Certainty is essential for scientific progress', 'Doubt drives the pursuit of scientific knowledge', 'Scientists should never reach conclusions', 'Searching is unrelated to scientific progress'], correct: 1, topic: 'Reading Comprehension', difficulty: 'easy', explanation: 'The passage states progress depends on doubt and that questioning keeps a scientist searching. Option (b) captures this; (a) contradicts the text, (c) overstates it, (d) is contradicted by the link drawn between searching and progress.' },
          { id: 'upsc-cse-s20-12', text: 'All poets are dreamers. Some dreamers are realists. Which conclusion necessarily follows?', options: ['All poets are realists', 'Some realists are poets', 'Some dreamers are poets', 'No realist is a poet'], correct: 2, topic: 'Logical Reasoning', difficulty: 'medium', explanation: 'From "All poets are dreamers" it follows that some dreamers are poets (the converse of a universal is a particular). The link between dreamers and realists is only partial, so nothing certain connects poets and realists. Hence only (c) necessarily follows.' },
          { id: 'upsc-cse-s20-13', text: 'Find the next term in the series: 5, 10, 20, 40, ?', options: ['60', '70', '80', '100'], correct: 2, topic: 'Number Series', difficulty: 'easy-medium', explanation: 'Each term is double the previous one: 40 × 2 = 80.' },
          { id: 'upsc-cse-s20-14', text: 'If 60% of a number is 90, what is 80% of the same number?', options: ['100', '110', '120', '135'], correct: 2, topic: 'Percentages', difficulty: 'medium', explanation: '60% of the number is 90, so the number = 90 ÷ 0.6 = 150. Then 80% of 150 = 0.8 × 150 = 120.' },
          { id: 'upsc-cse-s20-15', text: 'The average of four numbers is 18. If three of them are 12, 20 and 24, what is the fourth number?', options: ['14', '16', '18', '20'], correct: 1, topic: 'Averages', difficulty: 'easy-medium', explanation: 'Sum of four numbers = 4 × 18 = 72. The three given numbers total 12 + 20 + 24 = 56, so the fourth = 72 − 56 = 16.' },
          { id: 'upsc-cse-s20-16', text: 'In a class of 60 students, 35 play cricket, 30 play football, and 15 play both. How many play neither game?', options: ['5', '10', '15', '20'], correct: 1, topic: 'Basic Numeracy', difficulty: 'medium', explanation: 'Students playing at least one game = 35 + 30 − 15 = 50. Those playing neither = 60 − 50 = 10.' },
          { id: 'upsc-cse-s20-17', text: 'A boat travels downstream at 12 km/h and upstream at 8 km/h. What is the speed of the stream?', options: ['2 km/h', '4 km/h', '10 km/h', '1 km/h'], correct: 0, topic: 'Basic Numeracy', difficulty: 'medium-hard', explanation: 'Stream speed = (downstream − upstream) ÷ 2 = (12 − 8) ÷ 2 = 2 km/h.' },
          { id: 'upsc-cse-s20-18', text: 'A pie chart shows a family budget: Food 30%, Rent 25%, Savings 20%, Education 15%, Others 10%. If total monthly income is ₹40,000, how much more is spent on Food than on Education?', options: ['₹4,000', '₹5,000', '₹6,000', '₹7,000'], correct: 2, topic: 'Data Interpretation', difficulty: 'medium', explanation: 'Food = 30% of 40,000 = ₹12,000. Education = 15% of 40,000 = ₹6,000. Difference = 12,000 − 6,000 = ₹6,000.' },
          { id: 'upsc-cse-s20-19', text: 'If in a certain code "TABLE" is written as "UBCMF", how is "CHAIR" written in the same code?', options: ['DIBJS', 'DIBKS', 'DJBJS', 'DIAJS'], correct: 0, topic: 'Logical Reasoning', difficulty: 'easy-medium', explanation: 'Each letter is shifted forward by one position: T→U, A→B, B→C, L→M, E→F. Applying the same shift to CHAIR: C→D, H→I, A→B, I→J, R→S, giving DIBJS.' },
          { id: 'upsc-cse-s20-20', text: 'Two pipes can fill a tank in 12 minutes and 18 minutes respectively. If both are opened together, how long will they take to fill the tank?', options: ['6.6 minutes', '7.2 minutes', '7.5 minutes', '8 minutes'], correct: 1, topic: 'Basic Numeracy', difficulty: 'hard', explanation: 'Combined rate = 1/12 + 1/18 per minute. LCM 36: = 3/36 + 2/36 = 5/36 of the tank per minute. Time = 36/5 = 7.2 minutes.' },
        ]},
      ],
    },
    {
      id: 'upsc-cse-short-25',
      name: 'UPSC CSE Prelims — Short Mock (25 Questions)',
      template: 'nta',
      examCatalogueId: 'upsc-cse',
      kind: 'mock', scope: 'short', sectionTag: null,
      durationMin: 20,
      marking: { correct: 2, wrong: -0.66, unattempted: 0 },
      allowSectionSwitch: true, timerMode: 'full', calculator: false,
      questionTypes: ['mcq'], languages: ['en'],
      sections: [
        { id: 'gs1', name: 'General Studies I', questions: [
          { id: 'upsc-cse-s25-1', text: 'The Tropic of Cancer does NOT pass through which of the following states?', options: ['Gujarat', 'Madhya Pradesh', 'Odisha', 'Jharkhand'], correct: 2, topic: 'Geography', difficulty: 'medium', explanation: 'The Tropic of Cancer passes through Gujarat, Rajasthan, Madhya Pradesh, Chhattisgarh, Jharkhand, West Bengal, Tripura and Mizoram. Odisha lies just south of it and is not crossed.' },
          { id: 'upsc-cse-s25-2', text: 'Who among the following founded the Servants of India Society in 1905?', options: ['Bal Gangadhar Tilak', 'Gopal Krishna Gokhale', 'Lala Lajpat Rai', 'Bipin Chandra Pal'], correct: 1, topic: 'History', difficulty: 'medium', explanation: 'Gopal Krishna Gokhale founded the Servants of India Society in 1905 to train workers for the service of the nation through constitutional means.' },
          { id: 'upsc-cse-s25-3', text: 'Which writ is issued by a court to a public official to compel the performance of a public duty that the official has failed to do?', options: ['Habeas Corpus', 'Mandamus', 'Certiorari', 'Quo Warranto'], correct: 1, topic: 'Polity', difficulty: 'easy-medium', explanation: 'Mandamus ("we command") directs a public authority to perform a duty it has failed to perform. Habeas Corpus concerns unlawful detention, Certiorari quashes an order, and Quo Warranto challenges the holding of an office.' },
          { id: 'upsc-cse-s25-4', text: 'Which gas is the most abundant in the Earth\'s atmosphere by volume?', options: ['Oxygen', 'Carbon dioxide', 'Nitrogen', 'Argon'], correct: 2, topic: 'General Science', difficulty: 'easy', explanation: 'Nitrogen makes up about 78% of the atmosphere by volume, oxygen about 21%, argon about 0.93%, and carbon dioxide about 0.04%.' },
          { id: 'upsc-cse-s25-5', text: 'The "Mihrab" and "Minaret" are architectural features primarily associated with which type of structure?', options: ['Buddhist stupa', 'Hindu temple', 'Mosque', 'Jain basadi'], correct: 2, topic: 'Art and Culture', difficulty: 'easy-medium', explanation: 'A mihrab is the niche in a mosque indicating the direction of Mecca, and a minaret is the tower from which the call to prayer is given; both are features of Islamic mosque architecture.' },
          { id: 'upsc-cse-s25-6', text: 'In India, fiscal deficit is best defined as which of the following?', options: ['Total expenditure minus total receipts excluding borrowings', 'Revenue expenditure minus revenue receipts', 'Total expenditure minus total receipts including borrowings', 'Interest payments minus total receipts'], correct: 0, topic: 'Economy', difficulty: 'hard', explanation: 'Fiscal deficit is the excess of total expenditure over total receipts excluding borrowings; it indicates the total borrowing requirement of the government. Option (b) is the revenue deficit.' },
          { id: 'upsc-cse-s25-7', text: 'The Chipko movement, an early environmental campaign in India, was primarily aimed at protecting which resource?', options: ['Rivers from pollution', 'Forests from felling', 'Wetlands from drainage', 'Wildlife from poaching'], correct: 1, topic: 'Environment', difficulty: 'easy', explanation: 'The Chipko movement of the 1970s in the Himalayan region saw villagers hug trees to prevent contractors from felling them, making it a forest-protection movement.' },
          { id: 'upsc-cse-s25-8', text: 'Which of the following soils is most suitable for cotton cultivation and is formed from the weathering of volcanic rock?', options: ['Alluvial soil', 'Laterite soil', 'Black (regur) soil', 'Red soil'], correct: 2, topic: 'Geography', difficulty: 'medium', explanation: 'Black soil, also called regur, is formed by the weathering of Deccan basaltic (volcanic) lava and retains moisture well, making it ideal for cotton; it is also called black cotton soil.' },
          { id: 'upsc-cse-s25-9', text: 'The Preamble to the Indian Constitution declares India to be a sovereign, socialist, secular, democratic republic. The words "socialist" and "secular" were added by which amendment?', options: ['42nd Amendment Act, 1976', '44th Amendment Act, 1978', '24th Amendment Act, 1971', '52nd Amendment Act, 1985'], correct: 0, topic: 'Polity', difficulty: 'medium-hard', explanation: 'The 42nd Amendment Act of 1976 added the words "socialist", "secular" and "integrity" to the Preamble.' },
          { id: 'upsc-cse-s25-10', text: 'The "Ahom" dynasty, which resisted Mughal expansion for centuries, ruled in which region of India?', options: ['Assam', 'Bengal', 'Odisha', 'Kashmir'], correct: 0, topic: 'History', difficulty: 'medium-hard', explanation: 'The Ahoms ruled the Brahmaputra valley in Assam for about six centuries and famously defeated the Mughals at the Battle of Saraighat (1671) under Lachit Borphukan.' },
          { id: 'upsc-cse-s25-11', text: 'Which one of the following phenomena is responsible for the twinkling of stars?', options: ['Reflection of light', 'Atmospheric refraction', 'Total internal reflection', 'Dispersion of light'], correct: 1, topic: 'General Science', difficulty: 'medium', explanation: 'Stars twinkle because of atmospheric refraction: light from a star is refracted by turbulent layers of air of varying density, causing its apparent position and brightness to fluctuate.' },
          { id: 'upsc-cse-s25-12', text: 'The "Inner Line Permit" (ILP) regime, which regulates the entry of outsiders, is currently applicable in which set of states?', options: ['Punjab, Haryana, Himachal Pradesh', 'Arunachal Pradesh, Nagaland, Mizoram, Manipur', 'Kerala, Karnataka, Tamil Nadu', 'Bihar, Jharkhand, Odisha'], correct: 1, topic: 'Current Affairs Static', difficulty: 'hard', explanation: 'The Inner Line Permit, derived from the Bengal Eastern Frontier Regulation of 1873, currently applies in Arunachal Pradesh, Nagaland, Mizoram and Manipur, requiring outsiders to obtain a permit to enter.' },
          { id: 'upsc-cse-s25-13', text: 'The Konark Sun Temple, a UNESCO World Heritage Site built in the shape of a colossal chariot, is located in which state?', options: ['Odisha', 'Tamil Nadu', 'Karnataka', 'Madhya Pradesh'], correct: 0, topic: 'Art and Culture', difficulty: 'easy', explanation: 'The 13th-century Konark Sun Temple, built by King Narasimhadeva I of the Eastern Ganga dynasty in the form of the Sun God\'s chariot, is in Odisha and is a UNESCO World Heritage Site.' },
        ]},
        { id: 'csat', name: 'CSAT', questions: [
          { id: 'upsc-cse-s25-14', text: 'Read the passage: "A society that values only economic growth, while ignoring the health of its environment, mortgages its future for present comfort." The author primarily warns against:', options: ['All forms of economic growth', 'Sacrificing long-term environmental health for short-term gain', 'Protecting the environment at any cost', 'Ignoring present comfort entirely'], correct: 1, topic: 'Reading Comprehension', difficulty: 'medium', explanation: 'The passage criticises valuing growth while ignoring the environment, "mortgaging the future for present comfort", i.e. trading long-term environmental health for short-term gain. It does not condemn all growth (a) nor advocate the extremes in (c) and (d).' },
          { id: 'upsc-cse-s25-15', text: 'Q is the son of P. R is the brother of P. How is R related to Q?', options: ['Father', 'Uncle', 'Brother', 'Grandfather'], correct: 1, topic: 'Logical Reasoning', difficulty: 'medium', explanation: 'P is Q\'s parent, and R is P\'s brother, so R is the brother of Q\'s parent — i.e. Q\'s uncle.' },
          { id: 'upsc-cse-s25-16', text: 'Find the missing term: 1, 8, 27, 64, ?', options: ['100', '125', '150', '216'], correct: 1, topic: 'Number Series', difficulty: 'easy-medium', explanation: 'The terms are perfect cubes: 1³, 2³, 3³, 4³, so the next is 5³ = 125.' },
          { id: 'upsc-cse-s25-17', text: 'A number is first increased by 25% and then the result is decreased by 20%. What is the net change?', options: ['No change', '5% increase', '5% decrease', '10% increase'], correct: 0, topic: 'Percentages', difficulty: 'medium', explanation: 'Let the number = 100. After +25% = 125. After −20% of 125 = 125 × 0.8 = 100. The value returns to 100, so there is no net change.' },
          { id: 'upsc-cse-s25-18', text: 'The ratio of the ages of A and B is 3:5, and the sum of their ages is 64 years. What is B\'s age?', options: ['24 years', '32 years', '40 years', '48 years'], correct: 2, topic: 'Ratio', difficulty: 'easy-medium', explanation: 'Total parts = 3 + 5 = 8, so one part = 64/8 = 8 years. B has 5 parts = 5 × 8 = 40 years.' },
          { id: 'upsc-cse-s25-19', text: 'The average of 10 numbers is 25. If one number, 35, is removed, what is the average of the remaining nine numbers?', options: ['23.89', '24.44', '24.00', '25.00'], correct: 0, topic: 'Averages', difficulty: 'medium', explanation: 'Sum of 10 numbers = 10 × 25 = 250. After removing 35, sum = 250 − 35 = 215. New average = 215/9 = 23.89 (approximately).' },
          { id: 'upsc-cse-s25-20', text: 'Statements: All books are pens. No pen is a pencil. Which conclusion follows?', options: ['Some books are pencils', 'No book is a pencil', 'All pens are books', 'Some pencils are books'], correct: 1, topic: 'Logical Reasoning', difficulty: 'medium-hard', explanation: 'All books are pens, and no pen is a pencil; therefore no book can be a pencil. Hence "No book is a pencil" necessarily follows. The other options are not guaranteed.' },
          { id: 'upsc-cse-s25-21', text: 'A bar chart shows units sold over four months: Jan 120, Feb 150, Mar 90, Apr 180. By what percentage did April\'s sales exceed March\'s?', options: ['90%', '100%', '120%', '50%'], correct: 1, topic: 'Data Interpretation', difficulty: 'medium', explanation: 'Increase = 180 − 90 = 90. Percentage increase over March = (90/90) × 100 = 100%.' },
          { id: 'upsc-cse-s25-22', text: 'If 8 workers can build a wall in 10 days, how many days will 5 workers take to build the same wall, working at the same rate?', options: ['12 days', '14 days', '16 days', '18 days'], correct: 2, topic: 'Basic Numeracy', difficulty: 'medium', explanation: 'Total work = 8 × 10 = 80 worker-days. With 5 workers, days = 80/5 = 16 days.' },
          { id: 'upsc-cse-s25-23', text: 'A man spends 75% of his income. If his income increases by 20% and his expenditure increases by 10%, by what percentage do his savings increase?', options: ['30%', '40%', '50%', '60%'], correct: 2, topic: 'Percentages', difficulty: 'hard', explanation: 'Let income = 100, expenditure = 75, savings = 25. New income = 120, new expenditure = 75 × 1.10 = 82.5, new savings = 120 − 82.5 = 37.5. Increase in savings = (37.5 − 25)/25 × 100 = 50%.' },
          { id: 'upsc-cse-s25-24', text: 'In a row of 25 students, Ravi is 11th from the left. What is his position from the right?', options: ['13th', '14th', '15th', '16th'], correct: 2, topic: 'Logical Reasoning', difficulty: 'easy', explanation: 'Position from the right = total − position from left + 1 = 25 − 11 + 1 = 15th.' },
          { id: 'upsc-cse-s25-25', text: 'A train 150 metres long is moving at 54 km/h. How long will it take to completely cross a platform 250 metres long?', options: ['24 seconds', '26.67 seconds', '28 seconds', '30 seconds'], correct: 1, topic: 'Basic Numeracy', difficulty: 'hard', explanation: 'Speed = 54 km/h = 54 × 5/18 = 15 m/s. Total distance to cross = 150 + 250 = 400 m. Time = 400/15 = 26.67 seconds.' },
        ]},
      ],
    },
  ];
  window.EXAMS = (window.EXAMS || []).concat(mocks);
})();
